const tickets = [
  { id: 'ENG-451', type: 'feature', title: 'Add bulk CSV export for projects', jira_link: 'https://acme.atlassian.net/browse/ENG-451' },
  { id: 'ENG-412', type: 'feature', title: 'Implement SAML 2.0 SSO integration', jira_link: 'https://acme.atlassian.net/browse/ENG-412' },
  { id: 'ENG-438', type: 'feature', title: 'Recurring tasks — weekly and monthly cadence support', jira_link: 'https://acme.atlassian.net/browse/ENG-438' },
  { id: 'ENG-467', type: 'improvement', title: 'Increase pagination limit on project list endpoint from 50 to 500', jira_link: 'https://acme.atlassian.net/browse/ENG-467' },
  { id: 'ENG-471', type: 'improvement', title: 'Reduce search index rebuild time from 4s to 0.8s', jira_link: 'https://acme.atlassian.net/browse/ENG-471' },
  { id: 'ENG-455', type: 'improvement', title: 'Optimise dashboard initial load — lazy-load widgets', jira_link: 'https://acme.atlassian.net/browse/ENG-455' },
  { id: 'ENG-479', type: 'bugfix', title: 'Fix race condition on concurrent task status updates causing duplicate entries', jira_link: 'https://acme.atlassian.net/browse/ENG-479' },
  { id: 'ENG-461', type: 'bugfix', title: 'Fix email notifications sent twice when task assigned to multiple users', jira_link: 'https://acme.atlassian.net/browse/ENG-461' },
  { id: 'ENG-483', type: 'bugfix', title: 'Resolve 500 error on date filter when timezone offset is negative', jira_link: 'https://acme.atlassian.net/browse/ENG-483' },
  { id: 'ENG-475', type: 'security', title: 'Update JWT library to address CVE-2026-1234 — token expiry bypass', jira_link: 'https://acme.atlassian.net/browse/ENG-475' }
];
return [{ json: { tickets, version: '2.14.0', release_date: new Date().toISOString().split('T')[0] } }];

const { tickets, version, release_date } = $input.first().json;
const ticketText = tickets.map(t => `  [${t.type.toUpperCase()}] ${t.id}: ${t.title}`).join('\n');
const system = `You are a technical writer creating user-facing release notes. You translate engineering ticket titles into clear, benefit-focused language that non-technical users understand. Features get benefit statements. Bugs get 'fixed' framing. Security items get reassurance. Return ONLY valid JSON.`;
const user = `Generate release notes for version ${version} (${release_date}) from these ${tickets.length} tickets:

${ticketText}

Return JSON:
{
  "release_title": "string — engaging but not hyperbolic",
  "release_summary": "string — 2-3 sentences, what users should know about this release",
  "whats_new": [{ "title": "string", "description": "string — 1-2 sentences from user benefit perspective", "ticket_id": "string" }],
  "improvements": [{ "title": "string", "description": "string", "ticket_id": "string" }],
  "bug_fixes": [{ "title": "string", "description": "string", "ticket_id": "string" }],
  "security": [{ "title": "string", "description": "string", "ticket_id": "string" }],
  "full_text_markdown": "string — complete formatted release notes in GitHub Flavored Markdown"
}`;
return [{ json: { tickets, version, release_date, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Release Notes Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.full_text_markdown) return [{ json: { _error: true, reason: 'Missing full_text_markdown' } }];
return [{ json: { _error: false, notes: parsed, meta: { version: upstream.version, release_date: upstream.release_date, ticket_count: upstream.tickets.length, generated_at: new Date().toISOString() } } }];
